import React, { useState, useCallback, useEffect } from 'react';
import { Button, Input, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { ReceivablePayableDto } from '../../../services/kt/models';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { selectPlaceholderClass } from '../../../utils/selectField';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const CUSTOMER_TYPE_FILTER_OPTIONS = [
  { value: 'Customer', label: 'Khách hàng' },
  { value: 'Supplier', label: 'Nhà cung cấp' },
  { value: 'Both', label: 'Khách hàng & NCC' },
];

const CongNoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [asOfDate, setAsOfDate] = useState(new Date().toISOString().slice(0, 10));
  const [customerType, setCustomerType] = useState('');
  const [items, setItems] = useState<ReceivablePayableDto[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    ktService.getReceivablePayable({ asOfDate, customerType: customerType || undefined })
      .then(setItems)
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải công nợ'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [asOfDate, customerType, dispatch]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) handleLoad(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [handleLoad]);

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-users" /> Công nợ</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`erp-cong-no-filters`}>
        <Input type="date" value={asOfDate} onChange={e => setAsOfDate(e.target.value)} />
        <Select
          value={customerType}
          onChange={e => setCustomerType(e.target.value)}
          options={CUSTOMER_TYPE_FILTER_OPTIONS}
          placeholder="— Tất cả loại ĐT —"
          className={selectPlaceholderClass(customerType)}
        />
        <Button variant="primary" onClick={handleLoad} loading={loading}>Xem</Button>
        <ListSearchRefreshButtons testIdPrefix="erp-cong-no" onSearch={handleLoad} onRefresh={handleLoad} showSearch={false} />
      </div>
      <div className={erp.tableCard}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : items.length === 0 ? <div className={erp.empty}>Không có dữ liệu</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>Đối tượng</th><th>Loại</th><th className={erp.colRight}>Tổng Nợ</th><th className={erp.colRight}>Tổng Có</th><th className={erp.colRight}>Số dư</th></tr></thead>
              <tbody>{items.map(r => (
                <tr key={r.customerId}>
                  <td>{r.customerName}</td>
                  <td>{r.customerType}</td>
                  <td className={erp.colRight}>{formatVnd(r.totalDebit)}</td>
                  <td className={erp.colRight}>{formatVnd(r.totalCredit)}</td>
                  <td className={erp.colRight}>{formatVnd(r.balance)}</td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default CongNoPage;
